// Supported actions (POST /webhook/bubbleplan body):
//  { action: 'list' }
//  { action: 'create', title, type?, parent_id?, color?, description?, tags?, priority?, deadline? }
//  { action: 'update', id, patch: { ... } }
//  { action: 'delete', id }
//  { action: 'activeGoals' }  // convenience: goals with status=active
//  { action: 'markDone', id } // convenience: patch status=done

const raw = $input.first().json;
const body = (raw.body && raw.body.action) ? raw.body : raw;
const action = String(body.action || '').trim();
if (!action) {
  return [{ json: { _skip: true, error: 'no action', statusCode: 400 } }];
}

const token = $env.BUBBLEPLAN_TOKEN;
if (!token) {
  return [{ json: { _skip: true, error: 'BUBBLEPLAN_TOKEN not set on server', statusCode: 500 } }];
}

const base = 'https://bubbleplan.ru/v1';
let method = 'GET';
let url = base + '/bubbles';
let payload = null;

switch (action) {
  case 'list':
  case 'activeGoals':
    method = 'GET';
    break;
  case 'create':
    method = 'POST';
    payload = {
      title: String(body.title || '').trim(),
      type: body.type || 'goal'
    };
    if (body.parent_id) payload.parent_id = body.parent_id;
    if (body.color) payload.color = body.color;
    if (body.description) payload.description = body.description;
    if (Array.isArray(body.tags)) payload.tags = body.tags;
    if (body.priority) payload.priority = body.priority;
    if (body.deadline) payload.deadline = body.deadline;
    if (!payload.title) {
      return [{ json: { _skip: true, error: 'title required', statusCode: 400 } }];
    }
    break;
  case 'update':
  case 'markDone':
    if (!body.id) {
      return [{ json: { _skip: true, error: 'id required', statusCode: 400 } }];
    }
    method = 'PATCH';
    url = base + '/bubbles/' + encodeURIComponent(String(body.id));
    payload = (action === 'markDone') ? { status: 'done' } : (body.patch || {});
    break;
  case 'delete':
    if (!body.id) {
      return [{ json: { _skip: true, error: 'id required', statusCode: 400 } }];
    }
    method = 'DELETE';
    url = base + '/bubbles/' + encodeURIComponent(String(body.id));
    break;
  default:
    return [{ json: { _skip: true, error: 'unknown action: ' + action, statusCode: 400 } }];
}

return [{ json: { _skip: false, action, token, method, url, payload, filterActiveGoals: action === 'activeGoals' } }];

const res = $input.first().json;
const ctx = $('Route').first().json;
const action = ctx.action;

// httpRequest with neverError returns { statusCode, body, headers } at top level OR the body directly
const statusCode = res.statusCode || 200;
const raw = res.body != null ? res.body : res;
let parsed = raw;
if (typeof raw === 'string') {
  try { parsed = JSON.parse(raw); } catch(e) { parsed = { raw }; }
}

if (statusCode >= 400) {
  return [{ json: { ok: false, statusCode, error: parsed?.error || parsed?.message || 'bubbleplan error', raw: parsed } }];
}

// For list/activeGoals — normalize
if (action === 'list' || action === 'activeGoals') {
  const bubbles = parsed.bubbles || parsed.data || [];
  let filtered = bubbles;
  if (ctx.filterActiveGoals) {
    filtered = bubbles.filter(b => b.type === 'goal' && b.status === 'active');
  }
  return [{ json: { ok: true, total: parsed.total || filtered.length, bubbles: filtered } }];
}

return [{ json: { ok: true, result: parsed } }];
